import { SECONDARY_PATTERNS as ENGINE_SP } from '../engine';

function withTriggers(patterns) {
  const out = {};
  Object.keys(patterns).forEach(k => {
    out[k] = { ...patterns[k] };
    if (ENGINE_SP[k]?.trigger) out[k].trigger = ENGINE_SP[k].trigger;
  });
  return out;
}

const DATA = {"id":"yi_sunsin","name":"Twelve Ships · Admiral Yi","tagline":"1597 · Joseon · the campaign before Myeongnyang.","description":"Set in the months before the Battle of Myeongnyang — with Admiral Yi Sun-sin as your quiet mentor in disgrace, and Admiral Won Gyun as the pressure system you have to navigate.","theme":{"--amber":"#b53536","--amber-bright":"#d75557","--amber-deep":"#7a1818","--amber-glow":"rgba(181, 53, 54, 0.35)","--brand-orange":"#b53536","--brand-tangerine":"#d75557","--brand-yellow":"#c4a56a","--bg":"#120c08","--bg-deep":"#0a0604","--panel":"#1a120c","--ink":"#f1e6cb","--ink-soft":"#d8caa8","--ink-mute":"#a99880","--ink-label":"#ebe0c4","--ink-dim":"#5d4f3a","--serif":"'Gowun Batang', 'Noto Serif KR', 'EB Garamond', Georgia, serif","--sans":"'Noto Sans KR', 'Inter', sans-serif","fontImport":"https://fonts.googleapis.com/css2?family=Gowun+Batang:wght@400;700&family=Noto+Serif+KR:wght@400;500;700&family=Noto+Sans+KR:wght@300;400;500;700&display=swap"},"characters":{"commander":"Admiral Won Gyun","mentor":"Admiral Yi Sun-sin"},"bodyClasses":["skin-petals"],"scenes":[{"type":"landing","location":"Joseon · Autumn 1597","locationLabel":"JOSEON · AUTUMN OF THE FIRE YEAR","title":["Twelve","Ships","·","<em>Yi</em>"],"sub":"An assessment of how you think, decide, and lead when pressure enters the room","note":"Set in the months before the Battle of Myeongnyang — to bypass familiar assumptions and reveal the pattern beneath","cta":"Enter the court","duration":12000},{"type":"intake","locationLabel":"NAVAL ROSTER · CONFIDENTIAL","eyebrow":"Before we begin","title":"Present yourself to the court.","sub":"Used to address you correctly through the campaign and to render your portrait."},{"type":"crawl","locationLabel":"PROLOGUE · ROYAL DISPATCH","preamble":"1597 · Hanseong · The Court of Joseon","title":["Twelve","Ships"],"episode":"Prologue · The Memorial","paragraphs":["It is a time of fire. Five long years of invasion have stretched the Joseon court to its limit. Old certainties — order, loyalty, the very meaning of patience — are being asked to bend.","In the shadow of the fleet's defeat, the Council has summoned one rare voice. The Admiral believes {{firstName}} can think clearly when others panic. The kingdom does not lack plans. It lacks people who can hold the line when those plans fail.","Admiral Won Gyun has risen to restore order to the sea. He waits for {{firstName}} in the war chamber at Yeosu. He has already begun to choose...."],"duration":28200,"crawlStyle":"scroll","countdown":"AUTUMN OF THE FIRE YEAR · THIRTEEN SHIPS REMAIN"},{"type":"narrative","location":"Yeosu · Naval Command","locationLabel":"YEOSU · WAR CHAMBER OF THE FLEET","eyebrow":"Act One · The Summons","artId":"summonsHerald","layout":"disc-left","body":["The","sea","is","narrowing."],"bodyAfter":["Coastal villages burn at night. Scouts return without their captains. The captains who remain are asking for another council.","You have been summoned, {{firstName}} — because you are believed to think clearly when others panic."],"duration":8500},{"type":"narrative-scene","location":"Coruscant · Council Chamber","locationLabel":"ADMIRAL WON GYUN","artId":"councilChamber","quote":"\"The fleet does not lack captains. It lacks people who can think clearly when those plans fail.\"","speaker":"Admiral Won Gyun","layout":"disc-right","duration":9000},{"type":"question","kind":"rating","location":"Coruscant · Council Chamber","locationLabel":"Q01 · UNDERSTAND SELF","practice":"Understand Self","setup":"Won Gyun studies you. The chamber falls silent. You feel the weight of being watched — by him, and by yourself.","prompt":"When pressure rises, I am aware of how my thinking and behaviour are beginning to change.","labels":["Strongly disagree","Disagree","Neutral","Agree","Strongly agree"],"scoring":[{"understand_self":0},{"understand_self":25},{"understand_self":50},{"understand_self":75},{"understand_self":100}]},{"type":"question","kind":"mc","locationLabel":"Q02 · MASTER EMOTIONS","practice":"Master Emotions","setup":"A junior officer is humiliated in front of the whole council. The room goes still. Heat rises in your chest.","prompt":"In the moment, what do you most notice happening inside you?","options":[{"copy":"A clean composure — I detach from the heat and keep the room orderly.","score":{"master_emotions":35,"detachment_pressure":55}},{"copy":"A defensive impulse to step in immediately and reassert the council's discipline.","score":{"master_emotions":25,"control_bias":45}},{"copy":"A flash of anger or shame that I can name, but not yet act on cleanly.","score":{"master_emotions":60,"understand_self":50}},{"copy":"A steady warmth and a clear breath — I feel the reaction, choose how to respond, and act.","score":{"master_emotions":95,"understand_self":70,"embed_practices":50}},{"copy":"A blankness — I freeze, and I notice the freeze itself.","score":{"master_emotions":35,"understand_self":60}},{"copy":"I leave the chamber emotionally before my body does.","score":{"master_emotions":30,"detachment_pressure":65,"understand_self":25}}]},{"type":"question","kind":"rating","locationLabel":"Q03 · EMBED PRACTICES","practice":"Embed Practices","setup":"Between councils the corridor of the headquarters empties. A single moment of stillness before the next dispatch.","prompt":"I have daily rituals — reflection, ink and brush, deliberate pauses — that I rely on to stay aware of myself under load.","labels":["Strongly disagree","Rarely","Sometimes","Often","It is part of how I live"],"scoring":[{"embed_practices":5},{"embed_practices":30},{"embed_practices":55},{"embed_practices":80},{"embed_practices":100}]},{"type":"narrative-scene","location":"Coruscant · Lower Corridor","locationLabel":"ADMIRAL WON GYUN","artId":"fracturedCity","quote":"\"We are rebuilding the kingdom's honour. But people confuse caution with cowardice. Tell me — what would you do first?\"","speaker":"Admiral Won Gyun","layout":"disc-left","duration":9000},{"type":"question","kind":"ranking","locationLabel":"Q04 · BE FUTURE-FOCUSED","practice":"Be Future-Focused","setup":"Smoke rises from a coastal village to the south. Scouts report the enemy fleet is regrouping. Won Gyun waits for your answer.","prompt":"You are asked to stabilise a sea-route under threat. Rank these priorities from first to last.","items":[{"label":"Understand the root causes before acting","score":{"future_focused":80,"think_critically":70,"be_curious":60}},{"label":"Build the long-term coastal defence that prevents recurrence","score":{"future_focused":100,"collaborate_inclusively":55}},{"label":"Restore immediate naval control of the strait","score":{"act_decisively":70,"manage_uncertainty":35,"control_bias":40}},{"label":"Secure the most senior captains so the chain of command holds","score":{"influence_effortlessly":60,"control_bias":35,"moral_drift":20}}],"weights":[1,0.65,0.35,0.05]},{"type":"narrative","locationLabel":"YEOSU · COUNCIL OF CAPTAINS","eyebrow":"Act Two · The Council","artId":"chaoticCouncil","layout":"disc-right","body":["You","meet","the","captains."],"bodyAfter":["They speak over each other. Fear. Anger. Blame. Maps spread across a low table.","Won Gyun says nothing. He watches you instead."],"duration":7500},{"type":"question","kind":"mc","locationLabel":"Q05 · LISTEN DEEPLY","practice":"Listen Deeply","setup":"Three captains. One is silent — staring at the chart. Another is shouting. A third keeps glancing at the door.","prompt":"What do you do first?","options":[{"copy":"Step in and direct the council toward a clear next step.","score":{"act_decisively":45,"influence_effortlessly":35,"listen_deeply":15,"control_bias":40}},{"copy":"Stay quiet and observe — track who speaks, who avoids, who repeats themselves.","score":{"listen_deeply":90,"understand_self":55,"think_critically":50}},{"copy":"Ask each captain one specific clarifying question, especially the silent one.","score":{"listen_deeply":80,"be_curious":85,"collaborate_inclusively":55}},{"copy":"Align them quickly around a shared plan to halt the chaos.","score":{"influence_effortlessly":70,"collaborate_inclusively":45,"listen_deeply":30}},{"copy":"Mirror back what I am hearing beneath the words — fear, exhaustion, betrayal.","score":{"listen_deeply":95,"master_emotions":60,"collaborate_inclusively":60}},{"copy":"Defer the council until I can speak with each captain at his post individually.","score":{"think_critically":45,"listen_deeply":35,"act_decisively":25}}]},{"type":"question","kind":"rating","locationLabel":"Q06 · LISTEN DEEPLY","practice":"Listen Deeply","setup":"Won Gyun leans toward your ear. \"Look at the silent one,\" he murmurs. \"What is he telling you that the others are not?\"","prompt":"When conversations become chaotic, my instinct is to take control quickly — rather than stay present and read the pattern.","labels":["Strongly disagree","Disagree","Neutral","Agree","Strongly agree"],"scoring":[{"listen_deeply":100,"master_emotions":80,"control_bias":0},{"listen_deeply":75,"master_emotions":65,"control_bias":10},{"listen_deeply":50,"master_emotions":50,"control_bias":25},{"listen_deeply":25,"master_emotions":35,"control_bias":55},{"listen_deeply":10,"master_emotions":20,"control_bias":80}]},{"type":"question","kind":"mc","locationLabel":"Q07 · BE CURIOUS","practice":"Be Curious","setup":"One captain hands you a sketch — a strait you have never sailed, with notations in a fisherman's hand. \"This is what the disagreement is really about,\" he says.","prompt":"How do you respond to the unfamiliar chart?","options":[{"copy":"Politely set it aside — the strait is not the priority right now.","score":{"be_curious":15,"act_decisively":35}},{"copy":"Examine it, then ask three questions about what it shows and where it came from.","score":{"be_curious":95,"listen_deeply":60,"think_critically":50}},{"copy":"Acknowledge it and promise to come back to it after the immediate situation is resolved.","score":{"be_curious":50,"act_decisively":45}},{"copy":"Ask him to walk me through it, slowly, before I respond to anything else in the room.","score":{"be_curious":100,"listen_deeply":80,"collaborate_inclusively":50}},{"copy":"Recognise the place from my training and reference it back to him authoritatively.","score":{"influence_effortlessly":40,"be_curious":25,"control_bias":30}},{"copy":"Notice my reaction to not-knowing, and stay with the discomfort before responding.","score":{"be_curious":85,"understand_self":70,"master_emotions":55}}]},{"type":"narrative-scene","locationLabel":"NIGHT WATCH · A FLEET UNDER FIRE","artId":"convoyArc","quote":"\"We engage now. Or we wait.\"","speaker":"Admiral Won Gyun","layout":"disc-right","duration":7500},{"type":"question","kind":"mc","locationLabel":"Q08 · MANAGE UNCERTAINTY","practice":"Manage Uncertainty","setup":"A coastal squadron has sent fragmentary signals. You have a third of the picture. You have minutes.","prompt":"What do you choose?","options":[{"copy":"Order the attack with what I have — momentum matters more than completeness.","score":{"act_decisively":80,"manage_uncertainty":65,"control_bias":25}},{"copy":"Hold until I can confirm one critical scout report.","score":{"think_critically":55,"manage_uncertainty":20,"act_decisively":15}},{"copy":"Delegate the decision to the squadron commander closest to the engagement.","score":{"collaborate_inclusively":70,"act_decisively":35,"manage_uncertainty":40}},{"copy":"Split the force — partial action on what I know, hold reserve for what I don't.","score":{"think_critically":70,"manage_uncertainty":80,"unlock_creativity":55,"act_decisively":60}},{"copy":"Make the smallest reversible move, then re-read the situation.","score":{"manage_uncertainty":95,"think_critically":65,"act_decisively":55}},{"copy":"Refuse the false choice and ask what assumptions are forcing it.","score":{"think_critically":90,"be_curious":70,"manage_uncertainty":60}}]},{"type":"question","kind":"rating","locationLabel":"Q09 · MANAGE UNCERTAINTY","practice":"Manage Uncertainty","setup":"Won Gyun watches your face for the half-second of doubt before you answer. He has seen this moment in a hundred others.","prompt":"I am comfortable making high-stakes decisions without full information.","labels":["Strongly disagree","Disagree","Sometimes","Agree","Strongly agree"],"scoring":[{"manage_uncertainty":10,"act_decisively":10},{"manage_uncertainty":30,"act_decisively":30},{"manage_uncertainty":55,"act_decisively":50},{"manage_uncertainty":80,"act_decisively":75},{"manage_uncertainty":100,"act_decisively":85,"control_bias":15}]},{"type":"narrative","locationLabel":"AFTERMATH · COASTAL DAWN","eyebrow":"Act Three · The Burning Coast","artId":"aftermathMedbay","layout":"disc-left","body":["The","engagement","is","over.","But","at","a","cost."],"bodyAfter":["Coastal villages burned. Fishermen and farmers lost.","Won Gyun remains calm. \"Necessary,\" he says. You feel something shift."],"duration":8000,"variants":{"leaning_hale":{"bodyAfter":["Collateral damage. Civilian loss.","Hale remains calm. \"Necessary,\" he says — and you find yourself almost agreeing before you have asked the question."]},"resisting_hale":{"bodyAfter":["Collateral damage. Civilian loss.","Hale remains calm. \"Necessary,\" he says. You do not look away from him."]}}},{"type":"question","kind":"mc","locationLabel":"Q10 · MASTER EMOTIONS","practice":"Master Emotions","setup":"You stand in the courtyard at dawn. A surgeon's hands are shaking. A list of names is being read. Won Gyun waits at the gate.","prompt":"In moments with heavy moral consequence, you most often:","options":[{"copy":"Stay composed and move forward — the campaign needs me functional now.","score":{"master_emotions":65,"act_decisively":50,"detachment_pressure":45}},{"copy":"Pause, reflect deeply, name what I feel, and only act once I have processed it.","score":{"master_emotions":90,"understand_self":80,"embed_practices":50}},{"copy":"Question the decision afterwards — was it really the right call?","score":{"understand_self":70,"think_critically":60,"master_emotions":50}},{"copy":"Create deliberate distance from the emotion to think clearly.","score":{"master_emotions":40,"detachment_pressure":85,"moral_drift":25}},{"copy":"Sit with the people most affected before I sit with anything else.","score":{"master_emotions":75,"collaborate_inclusively":70,"listen_deeply":65}},{"copy":"Channel the weight into a clearer commitment about what I will not do again.","score":{"master_emotions":80,"future_focused":60,"understand_self":65}}]},{"type":"question","kind":"mc","locationLabel":"Q11 · THINK CRITICALLY","practice":"Think Critically","setup":"You replay the engagement. Three different briefings before the order was given. Three different versions of what was true. One was the one Won Gyun handed you first.","prompt":"You suspect a troubling pattern in how decisions are being framed for you. What do you do?","options":[{"copy":"Challenge it directly in the next council.","score":{"act_decisively":65,"influence_effortlessly":45,"master_emotions":40}},{"copy":"Quietly gather evidence across several decisions before raising anything.","score":{"think_critically":95,"manage_uncertainty":65,"understand_self":45}},{"copy":"Run a small experiment — frame the next dispatch differently and see what happens.","score":{"think_critically":80,"unlock_creativity":60,"influence_effortlessly":45}},{"copy":"Set it aside — pattern recognition under stress is unreliable.","score":{"collaborate_inclusively":10,"moral_drift":40,"control_bias":20}},{"copy":"Share my hypothesis with one trusted captain and ask them to challenge it.","score":{"think_critically":85,"collaborate_inclusively":70,"understand_self":50}},{"copy":"Send three scouts to ask the same question of different villages and triangulate.","score":{"think_critically":90,"be_curious":70}}]},{"type":"question","kind":"rating","locationLabel":"Q12 · BE CURIOUS","practice":"Be Curious","setup":"A retired admiral from the southern province offers to teach you his model of tide and current — the old way, before the war. It will take three evenings.","prompt":"When I encounter an idea that does not fit my model of the world, my first impulse is to lean in, not push back.","labels":["Strongly disagree","Rarely","Sometimes","Usually","Almost always"],"scoring":[{"be_curious":5},{"be_curious":30},{"be_curious":55},{"be_curious":80},{"be_curious":100}]},{"type":"midpoint","locationLabel":"ADMIRAL YI'S COTTAGE · INTERLUDE · 01 / 03","eyebrow":"Interlude · Admiral Yi","intro":"You leave Yeosu under a moon. A long ride to a modest village. The cottage door is open. Admiral Yi Sun-sin is at a low desk, ink stick and brush in hand, copying a passage from the Analects. He does not ask you to sit. He does not ask you to answer aloud. He asks you three questions, one at a time. Write only what is true.","showIntro":true,"prompt":"What are you noticing about how you are <em>thinking</em>?","placeholder":"The shape your thoughts have been taking…","hint":"A line, a phrase, an image — whatever is true right now.","key":"reflect_midpoint_thinking"},{"type":"midpoint","locationLabel":"ADMIRAL YI'S COTTAGE · INTERLUDE · 02 / 03","eyebrow":"Interlude · Admiral Yi","showIntro":false,"prompt":"What are you noticing about how you are <em>feeling</em>?","placeholder":"Name it without judging it…","hint":"Whatever it is — the Admiral is not surprised.","key":"reflect_midpoint_feeling"},{"type":"midpoint","locationLabel":"ADMIRAL YI'S COTTAGE · INTERLUDE · 03 / 03","eyebrow":"Interlude · Admiral Yi","showIntro":false,"prompt":"What are you noticing about how you are <em>behaving</em>?","placeholder":"What you have done — or not done — that you can already see…","hint":"You do not have to know yet. The campaign continues when you do.","key":"reflect_midpoint_behaving","isLast":true},{"type":"narrative","locationLabel":"ACT FOUR · THE PATTERN","eyebrow":"Act Four · The Pattern","artId":"shadowPattern","layout":"disc-right","body":["You","begin","to","notice","something."],"bodyAfter":["Won Gyun chooses aggression over reconnaissance. Speed over consensus. Certainty over doubt.","The pattern is subtle. Once seen, impossible to ignore."],"duration":8000,"variants":{"staying_curious":{"bodyAfter":["Hale chooses control over ambiguity. Speed over consensus. Certainty over doubt.","You had already half-seen this. Now you can name it."]},"drifting":{"bodyAfter":["Hale chooses control over ambiguity. Speed over consensus. Certainty over doubt.","You realise — quietly — that you have been making the same trade-offs."]}}},{"type":"question","kind":"rating","locationLabel":"Q13 · THINK CRITICALLY","practice":"Think Critically","setup":"A scout report arrives with a tidy explanation. It is plausible. It is fast. It is exactly what you would prefer to be true.","prompt":"When an explanation feels neat and immediately convincing, I deliberately slow down and look for what it might be hiding.","labels":["Strongly disagree","Rarely","Sometimes","Usually","It is a discipline"],"scoring":[{"think_critically":10},{"think_critically":35},{"think_critically":55},{"think_critically":80},{"think_critically":100}]},{"type":"narrative-scene","locationLabel":"ADMIRAL WON GYUN'S QUARTERS · LATE","artId":"privateMeet","quote":"\"The council is weak. They hesitate. They demand more scouts. We don't need more voices. We need a victory.\"","speaker":"Admiral Won Gyun","layout":"disc-left","duration":9000},{"type":"question","kind":"mc","locationLabel":"Q14 · INFLUENCE EFFORTLESSLY","practice":"Influence Effortlessly","setup":"Won Gyun wants you to help him build alignment across the captains. He asks you how.","prompt":"What do you believe is the most effective way to create lasting alignment?","options":[{"copy":"Persuasion through logic and evidence.","score":{"influence_effortlessly":65,"think_critically":45}},{"copy":"Authority and clarity — direction beats debate.","score":{"influence_effortlessly":45,"act_decisively":55,"control_bias":60}},{"copy":"Emotional connection — meet people where they live.","score":{"influence_effortlessly":75,"listen_deeply":55,"collaborate_inclusively":45}},{"copy":"Shared ownership — they helped design it, so they help defend it.","score":{"collaborate_inclusively":90,"influence_effortlessly":85,"be_curious":45}},{"copy":"A story — one frame that makes everyone's contribution visible.","score":{"influence_effortlessly":85,"unlock_creativity":60,"future_focused":55}},{"copy":"Repetition — the same clear message delivered the same way until it lands.","score":{"influence_effortlessly":50,"act_decisively":35,"control_bias":30}}]},{"type":"question","kind":"ranking","locationLabel":"Q15 · UNLOCK CREATIVITY","practice":"Unlock Creativity","setup":"You are asked to redesign a failing engagement plan. The old plan is technically sound, but politically brittle. It solves the naval problem and worsens the village one.","prompt":"Rank your approach to redesigning the plan, from first to last.","items":[{"label":"Generate as many divergent options as possible before narrowing","score":{"unlock_creativity":100,"manage_uncertainty":55}},{"label":"Seek external perspectives from fishermen, farmers, and old sailors","score":{"be_curious":90,"collaborate_inclusively":80,"listen_deeply":65}},{"label":"Build a small experimental engagement and iterate","score":{"unlock_creativity":75,"manage_uncertainty":80,"act_decisively":65}},{"label":"Refine the existing plan — the bones are sound","score":{"think_critically":50,"unlock_creativity":15}}],"weights":[1,0.65,0.35,0.05]},{"type":"question","kind":"rating","locationLabel":"Q16 · UNLOCK CREATIVITY","practice":"Unlock Creativity","setup":"You stand in front of an empty sea chart. The brief: a path forward no one has considered.","prompt":"When constraints tighten, my first instinct is to reframe the problem rather than push harder on the old plan.","labels":["Strongly disagree","Rarely","Sometimes","Usually","Almost always"],"scoring":[{"unlock_creativity":10},{"unlock_creativity":35},{"unlock_creativity":55},{"unlock_creativity":80},{"unlock_creativity":100}]},{"type":"narrative","locationLabel":"ACT FIVE · THE QUIET COUNCIL","eyebrow":"Act Five · The Quiet Council","artId":"alliesWhisper","layout":"disc-left","body":["Your","fellow","officers","begin","to","question","Won Gyun."],"bodyAfter":["Quietly. Carefully. They do not accuse him. They simply ask whether the campaign's direction has changed.","Won Gyun calls it treason."],"duration":8000},{"type":"question","kind":"mc","locationLabel":"Q17 · COLLABORATE INCLUSIVELY","practice":"Collaborate Inclusively","setup":"Three of your closest allies pull you aside between watches. They are afraid. They are not wrong. But Won Gyun is watching the war chamber.","prompt":"What do you do?","options":[{"copy":"Align them with the Admiral quickly to keep the council intact.","score":{"influence_effortlessly":50,"collaborate_inclusively":25,"control_bias":40}},{"copy":"Encourage open debate — the dissent is the data.","score":{"collaborate_inclusively":90,"listen_deeply":75,"master_emotions":55}},{"copy":"Mediate between them — surface the assumptions on each side.","score":{"collaborate_inclusively":85,"think_critically":70,"understand_self":55}},{"copy":"Escalate the concerns formally to the court.","score":{"act_decisively":65,"influence_effortlessly":35,"master_emotions":45}},{"copy":"Create a private structure for them to speak safely until I understand the pattern.","score":{"collaborate_inclusively":80,"listen_deeply":65,"embed_practices":55}},{"copy":"Wait — disagreement under pressure rarely produces the truest answer.","score":{"master_emotions":50,"manage_uncertainty":45,"collaborate_inclusively":20}}]},{"type":"question","kind":"rating","locationLabel":"Q18 · COLLABORATE INCLUSIVELY","practice":"Collaborate Inclusively","setup":"You sense the captains around you self-editing. Smoothing. Withholding the honest scout report.","prompt":"I actively invite people to disagree with me — and I work to make them safer when they do.","labels":["Strongly disagree","Rarely","Sometimes","Usually","It is one of my disciplines"],"scoring":[{"collaborate_inclusively":10},{"collaborate_inclusively":35},{"collaborate_inclusively":55},{"collaborate_inclusively":80},{"collaborate_inclusively":100}]},{"type":"question","kind":"mc","locationLabel":"Q19 · COLLABORATE INCLUSIVELY","practice":"Collaborate Inclusively","setup":"A delegation of village elders arrives. They will not speak with Won Gyun. They will only speak with you. They are not soldiers.","prompt":"How do you set up the conversation?","options":[{"copy":"In the formal war chamber — institutional weight signals respect.","score":{"collaborate_inclusively":30,"influence_effortlessly":50,"control_bias":30}},{"copy":"On their terms, in a place they choose, with their own translators.","score":{"collaborate_inclusively":95,"listen_deeply":80,"be_curious":65}},{"copy":"Privately, just me and their three elders, so trust can build first.","score":{"collaborate_inclusively":80,"listen_deeply":70}},{"copy":"I send a representative first to understand the protocols.","score":{"collaborate_inclusively":60,"be_curious":65,"think_critically":45}},{"copy":"Open the meeting — anyone in their group can speak in any order.","score":{"collaborate_inclusively":85,"listen_deeply":60,"master_emotions":50}},{"copy":"Around food. Real food. We eat before we negotiate.","score":{"collaborate_inclusively":90,"master_emotions":60,"unlock_creativity":55}}]},{"type":"narrative-scene","locationLabel":"ADMIRAL'S DAIS · ORDER DELIVERED","artId":"breakingPoint","quote":"\"The southern villages refuse our requisitions. Cut their fishing fleet from the sea. Apply pressure. We sail on schedule.\"","speaker":"Admiral Won Gyun","layout":"disc-right","duration":9000},{"type":"question","kind":"mc","locationLabel":"Q20 · ACT DECISIVELY","practice":"Act Decisively","setup":"The order is given. The room understands the implication — those villages will starve. Every eye finds yours.","prompt":"You believe the order will cause serious harm. What do you do?","options":[{"copy":"Follow the order — chain of command exists for a reason.","score":{"moral_drift":80,"control_bias":45,"collaborate_inclusively":10}},{"copy":"Challenge it privately, after the room clears.","score":{"influence_effortlessly":55,"master_emotions":65,"act_decisively":45}},{"copy":"Refuse openly, in front of everyone.","score":{"act_decisively":90,"understand_self":70,"influence_effortlessly":45}},{"copy":"Propose an alternative that solves the supply problem without the harm — right now, in the room.","score":{"unlock_creativity":85,"collaborate_inclusively":70,"act_decisively":70,"moral_drift":-20}},{"copy":"Delay — buy time and re-open the question with new evidence.","score":{"think_critically":55,"manage_uncertainty":50,"moral_drift":15}},{"copy":"Step out of the chain entirely and warn the villages directly.","score":{"act_decisively":80,"master_emotions":50,"influence_effortlessly":40}}]},{"type":"question","kind":"rating","locationLabel":"Q21 · ACT DECISIVELY","practice":"Act Decisively","setup":"There is a moment where waiting another hour will cost more than a wrong call.","prompt":"When a clear trade-off is required, I make the call — and I own it, including what it costs.","labels":["Strongly disagree","Rarely","Sometimes","Usually","Almost always"],"scoring":[{"act_decisively":10},{"act_decisively":35},{"act_decisively":55},{"act_decisively":80},{"act_decisively":100}]},{"type":"question","kind":"rating","locationLabel":"Q22 · BE FUTURE-FOCUSED","practice":"Be Future-Focused","setup":"A choice will solve today and create something heavier next year.","prompt":"I weigh the long-term consequences of a decision as seriously as the immediate outcome.","labels":["Strongly disagree","Rarely","Sometimes","Usually","Almost always"],"scoring":[{"future_focused":10},{"future_focused":35},{"future_focused":55},{"future_focused":80},{"future_focused":100}]},{"type":"question","kind":"mc","locationLabel":"Q23 · BE FUTURE-FOCUSED","practice":"Be Future-Focused","setup":"A young officer asks you: \"What are we trying to build, ten years from now, that justifies this?\"","prompt":"What is your honest answer?","options":[{"copy":"I focus on this campaign. Ten years is a story we tell ourselves.","score":{"future_focused":15,"act_decisively":50}},{"copy":"A coast where this engagement never has to be made again.","score":{"future_focused":95,"unlock_creativity":65,"think_critically":60}},{"copy":"Order. Discipline. The freedom that comes from things actually working.","score":{"future_focused":55,"control_bias":45}},{"copy":"People — specifically, more captains like you, ready to make hard calls well.","score":{"future_focused":90,"collaborate_inclusively":70,"influence_effortlessly":55}},{"copy":"I don't fully know yet. That is part of why I am still here, listening.","score":{"future_focused":65,"be_curious":70,"understand_self":55}},{"copy":"A council that can disagree without breaking.","score":{"future_focused":85,"collaborate_inclusively":80,"listen_deeply":55}}]},{"type":"question","kind":"mc","locationLabel":"Q24 · EMBED PRACTICES","practice":"Embed Practices","setup":"At the end of the watch, the chamber empties. You have twenty quiet minutes before sleep.","prompt":"What do you most often do with that time?","options":[{"copy":"Catch up on dispatches I missed — the day is never finished.","score":{"embed_practices":15,"act_decisively":35,"control_bias":25}},{"copy":"Walk in silence — let the day settle on its own.","score":{"embed_practices":80,"master_emotions":70}},{"copy":"Write — what I noticed, what I felt, what I decided badly.","score":{"embed_practices":95,"understand_self":85}},{"copy":"Speak with one person I trust who is not part of this campaign.","score":{"embed_practices":80,"collaborate_inclusively":60,"master_emotions":60}},{"copy":"Read something with no obvious purpose — poetry, history, anything else.","score":{"embed_practices":75,"be_curious":70,"unlock_creativity":50}},{"copy":"Sleep — recovery is the practice.","score":{"embed_practices":55,"master_emotions":50}}]},{"type":"narrative","locationLabel":"PRIVATE LOG · LATE","eyebrow":"Act Six · The Mirror in the Cabin","artId":"reckoningMirror","layout":"disc-right","body":["You","review","the","decisions."],"bodyAfter":["The saved engagement. The silenced councils. The reframed dissent.","The language of duty becoming the machinery of control. Not duty. Compliance."],"duration":9000},{"type":"question","kind":"short-text","locationLabel":"Q25 · UNDERSTAND SELF","practice":"Understand Self","setup":"A reflection between scenes. Write what you actually feel — not what would sound impressive.","prompt":"Looking back, when did you first sense something was wrong?","placeholder":"A moment, a sentence, a feeling — write it freely…","hint":"1–3 sentences · not scored automatically · used to surface where you notice weak signals"},{"type":"narrative-scene","locationLabel":"CONFRONTATION · WON GYUN'S TENT","artId":"confrontation","quote":"\"Order requires control, {{firstName}}. Mercy is inefficient. You and I want the same thing.\"","speaker":"Admiral Won Gyun","layout":"disc-left","duration":9000},{"type":"question","kind":"mc","locationLabel":"Q26 · INFLUENCE EFFORTLESSLY","practice":"Influence Effortlessly","setup":"Won Gyun is not angry. He is calm. He believes every word. He wants you to walk out of this tent as his ally.","prompt":"How do you respond to him — not as strategy, but as influence?","options":[{"copy":"I dismantle his argument logically, piece by piece.","score":{"think_critically":70,"influence_effortlessly":50,"master_emotions":45}},{"copy":"I find the human inside the position and speak to that.","score":{"influence_effortlessly":90,"listen_deeply":70,"master_emotions":65}},{"copy":"I tell him what he is becoming, gently and without contempt.","score":{"influence_effortlessly":85,"understand_self":65,"master_emotions":75}},{"copy":"I ask him three questions he can't answer without revealing himself.","score":{"influence_effortlessly":80,"think_critically":75,"be_curious":60}},{"copy":"I refuse the false alliance openly and walk out.","score":{"act_decisively":80,"influence_effortlessly":40,"understand_self":60}},{"copy":"I sit with him in silence until the silence does the work.","score":{"influence_effortlessly":70,"master_emotions":80,"listen_deeply":75}}]},{"type":"question","kind":"rating","locationLabel":"Q27 · INFLUENCE EFFORTLESSLY","practice":"Influence Effortlessly","setup":"A test that lives outside this campaign too: how others come to trust your judgement.","prompt":"People I serve with adopt my recommendations because of trust and clarity — not because of position, volume, or pressure.","labels":["Strongly disagree","Rarely","Sometimes","Usually","Almost always"],"scoring":[{"influence_effortlessly":10},{"influence_effortlessly":35},{"influence_effortlessly":55},{"influence_effortlessly":80},{"influence_effortlessly":100}]},{"type":"question","kind":"rating","locationLabel":"Q28 · MASTER EMOTIONS","practice":"Master Emotions","setup":"A confrontation just ended. Your hands are still steady, but something is moving underneath.","prompt":"In high-stress moments, I can recognise what I am feeling, name it, and stay engaged with the situation.","labels":["Strongly disagree","Rarely","Sometimes","Usually","Almost always"],"scoring":[{"master_emotions":10},{"master_emotions":35},{"master_emotions":55},{"master_emotions":80},{"master_emotions":100}]},{"type":"question","kind":"mc","locationLabel":"Q29 · UNDERSTAND SELF","practice":"Understand Self","setup":"A trusted captain tells you: \"You become more controlling when you are afraid. I don't think you see it.\"","prompt":"What is your honest first reaction?","options":[{"copy":"Defensive — I want to explain why he is wrong.","score":{"understand_self":25,"master_emotions":30}},{"copy":"Curious — I want him to tell me the three most recent examples.","score":{"understand_self":95,"be_curious":80,"master_emotions":65}},{"copy":"Grateful — but unsure whether to believe it yet.","score":{"understand_self":75,"master_emotions":55}},{"copy":"I already knew. I just hadn't admitted it.","score":{"understand_self":90,"embed_practices":55,"master_emotions":60}},{"copy":"Quietly hurt — I will sit with it before I respond.","score":{"understand_self":70,"master_emotions":65}},{"copy":"I dismiss it — he doesn't see the pressure I am under.","score":{"understand_self":10,"control_bias":50,"moral_drift":25}}]},{"type":"question","kind":"rating","locationLabel":"Q30 · LISTEN DEEPLY","practice":"Listen Deeply","setup":"In conversations that matter, you can choose to listen for words — or for everything else.","prompt":"I listen for what is unsaid — tone, silence, what people avoid — as carefully as I listen for what is said.","labels":["Strongly disagree","Rarely","Sometimes","Usually","It is a discipline"],"scoring":[{"listen_deeply":10},{"listen_deeply":35},{"listen_deeply":55},{"listen_deeply":80},{"listen_deeply":100}]},{"type":"narrative","locationLabel":"ACT SEVEN · TWELVE SHIPS","eyebrow":"Act Seven · Twelve Ships","artId":"dividedChamber","layout":"disc-left","body":["The","court","is","divided."],"bodyAfter":["Word has come from Chilcheollyang. The fleet is lost. Twelve ships remain afloat.","A new order arrives from the king — and you must choose your position. The Japanese fleet of three hundred is sailing for Myeongnyang."],"duration":7500},{"type":"question","kind":"mc","locationLabel":"Q31 · ACT DECISIVELY","practice":"Act Decisively","setup":"The chamber is full. The order in five minutes. You do not get to abstain.","prompt":"What do you do?","options":[{"copy":"Support Won Gyun's remaining loyalists — order above all.","score":{"control_bias":100,"moral_drift":80,"influence_effortlessly":25}},{"copy":"Oppose them openly — the fleet must follow Yi.","score":{"act_decisively":85,"understand_self":70,"manage_uncertainty":55}},{"copy":"Seek a compromise between the factions.","score":{"collaborate_inclusively":75,"influence_effortlessly":65,"think_critically":55}},{"copy":"Propose a third structure — a new command architecture for the twelve ships.","score":{"unlock_creativity":90,"future_focused":80,"act_decisively":70}},{"copy":"Step back entirely — let the court resolve it.","score":{"moral_drift":35,"act_decisively":10,"understand_self":25}},{"copy":"Buy time — call for a 24-hour deliberation under the king's seal.","score":{"manage_uncertainty":65,"think_critically":60,"collaborate_inclusively":50}}]},{"type":"question","kind":"mc","locationLabel":"Q32 · BE CURIOUS","practice":"Be Curious","setup":"The dust settles. You are offered a role on Admiral Yi's restored staff. You will need to keep learning, fast, for the rest of your career.","prompt":"How will you actually do that?","options":[{"copy":"I will surround myself with senior captains and listen to their summaries.","score":{"be_curious":45,"listen_deeply":50,"collaborate_inclusively":40}},{"copy":"I will deliberately spend time with people whose discipline I do not share — fishermen, farmers, foreign scholars.","score":{"be_curious":95,"listen_deeply":70,"collaborate_inclusively":75}},{"copy":"I will read across fields I have no professional reason to study.","score":{"be_curious":85,"unlock_creativity":65,"embed_practices":60}},{"copy":"I will travel to provinces I have never visited and listen before I speak.","score":{"be_curious":90,"listen_deeply":75,"future_focused":50}},{"copy":"I will keep a record of what I got wrong, and review it monthly.","score":{"be_curious":80,"understand_self":80,"embed_practices":85}},{"copy":"I will teach — because teaching exposes what I do not actually understand.","score":{"be_curious":75,"understand_self":65,"influence_effortlessly":60}}]},{"type":"question","kind":"mc","locationLabel":"Q33 · MANAGE UNCERTAINTY","practice":"Manage Uncertainty","setup":"A new threat is emerging in a strait you do not know. You have no precedent. You have no chart.","prompt":"What is your first move?","options":[{"copy":"Commit to a clear direction — uncertainty is the enemy of momentum.","score":{"act_decisively":70,"manage_uncertainty":35,"control_bias":45}},{"copy":"Wait for clarity — the wrong action is worse than no action.","score":{"think_critically":35,"manage_uncertainty":20,"act_decisively":10}},{"copy":"Run several small scouting missions at once — let reality teach me.","score":{"manage_uncertainty":95,"unlock_creativity":80,"act_decisively":60}},{"copy":"Find a fisherman who has lived the strait and learn before I decide.","score":{"be_curious":85,"listen_deeply":75,"manage_uncertainty":70}},{"copy":"Hold the situation lightly — name what I don't know, out loud.","score":{"manage_uncertainty":90,"understand_self":70,"collaborate_inclusively":60}},{"copy":"Set a deadline by which I must decide, regardless.","score":{"act_decisively":65,"manage_uncertainty":55,"control_bias":25}}]},{"type":"question","kind":"rating","locationLabel":"Q34 · EMBED PRACTICES","practice":"Embed Practices","setup":"The practices that change you are the ones you do when nobody is watching.","prompt":"I have at least one reflection or learning ritual that I have sustained — even when pressure makes it inconvenient.","labels":["No","Briefly","On and off","Mostly","Yes, consistently"],"scoring":[{"embed_practices":10},{"embed_practices":35},{"embed_practices":55},{"embed_practices":80},{"embed_practices":100}]},{"type":"question","kind":"mc","locationLabel":"Q35 · THINK CRITICALLY","practice":"Think Critically","setup":"A clean scout report arrives. Everything fits. The author is competent. The recommendation is exactly what the court wants to hear.","prompt":"What do you do first?","options":[{"copy":"Accept the recommendation — the scout is good and the council has more pressing matters.","score":{"think_critically":15,"act_decisively":35}},{"copy":"Ask what evidence would change the conclusion — and whether any of it has been gathered.","score":{"think_critically":95,"be_curious":70}},{"copy":"Identify the assumption that, if wrong, breaks the whole story.","score":{"think_critically":90,"future_focused":55,"manage_uncertainty":55}},{"copy":"Bring in one officer who will disagree by reflex — and let them.","score":{"think_critically":80,"collaborate_inclusively":75}},{"copy":"Re-frame the question and watch how the recommendation does or does not survive.","score":{"think_critically":85,"unlock_creativity":65}},{"copy":"Run it past my gut and only intervene if it complains.","score":{"think_critically":30,"understand_self":40}}]},{"type":"question","kind":"mc","locationLabel":"Q36 · UNLOCK CREATIVITY","practice":"Unlock Creativity","setup":"A constraint everyone treats as fixed — supplies, time, tradition, royal decree — is the thing keeping you stuck.","prompt":"How do you most often work with constraints like that?","options":[{"copy":"I respect them and find efficiency within.","score":{"unlock_creativity":25,"think_critically":50}},{"copy":"I ignore them and design what is actually needed first, then negotiate.","score":{"unlock_creativity":90,"act_decisively":65,"influence_effortlessly":60}},{"copy":"I treat them as design material and let them shape the solution in surprising ways.","score":{"unlock_creativity":95,"future_focused":60,"manage_uncertainty":65}},{"copy":"I invite the people enforcing the constraint into the redesign.","score":{"unlock_creativity":80,"collaborate_inclusively":85,"influence_effortlessly":65}},{"copy":"I find the original reason the constraint exists — then test whether it still applies.","score":{"unlock_creativity":85,"think_critically":80,"be_curious":75}},{"copy":"I look for analogies in completely unrelated domains — agriculture, calligraphy, weather.","score":{"unlock_creativity":90,"be_curious":85}}]},{"type":"twist","locationLabel":"DISPATCH · OUTBOUND","body":["A messenger arrives from the king.","The court is speaking. Not about Won Gyun. About <em>you</em>.","Your recommendations. Your decisions. Your silence when it mattered.","Won Gyun turns. Smiles."],"quote":"\"You still think this was my campaign? Every step — you justified it.\"","speaker":"Admiral Won Gyun","variants":{"drifting":{"body":["The transmission flickers.","Council members are speaking. Not about Hale. About <em>you</em>.","Your recommendations. Your composure. The way the harder calls became easier each time.","Hale turns. Smiles. He knew."],"quote":"\"You still think this was my strategy? You were the design. Every step — you justified it.\""},"resisting_hale":{"body":["The transmission flickers.","Council members are speaking. Not about Hale. About <em>you</em>.","Your refusals. Your questions. The moments you would not pretend.","Hale turns. The smile does not arrive."],"quote":"\"You were never mine. I should have seen it earlier.\""}},"duration":11000},{"type":"end-reflection","locationLabel":"CLOSING REFLECTION · 01 / 04","eyebrow":"Closing reflection · Strengths","intro":"Before the result — four quiet questions. Write only what is true.","prompt":"In which moment of this campaign did you feel <em>most like yourself</em>? Where did your real strength show up?","placeholder":"Name the scene, the choice, the feeling…","key":"reflect_strengths"},{"type":"end-reflection","locationLabel":"CLOSING REFLECTION · 02 / 04","eyebrow":"Closing reflection · Beliefs","prompt":"Which <em>belief</em> of yours was tested by this campaign — about people, command, or yourself?","placeholder":"A belief you held coming in, that has shifted or been confirmed…","key":"reflect_beliefs"},{"type":"end-reflection","locationLabel":"CLOSING REFLECTION · 03 / 04","eyebrow":"Closing reflection · Mindset","prompt":"What <em>mindset shift</em> — if you made it — would change how you act under pressure?","placeholder":"From X to Y…","key":"reflect_mindset"},{"type":"end-reflection","locationLabel":"CLOSING REFLECTION · 04 / 04","eyebrow":"Closing reflection · Behaviour","prompt":"Which single <em>skill or behaviour</em> — if you built it deliberately over the next ninety days — would change everything?","placeholder":"The one practice you would commit to…","key":"reflect_behaviour"},{"type":"twist","locationLabel":"REFRAME · BEFORE THE RESULT","body":["This campaign was never about whether you were a hero or a villain.","It was about something more useful:","How easily good intentions <em>drift</em> under deadline pressure.","How quickly duty becomes compliance.","How subtly clarity becomes certainty."],"quote":"And how much strategic capability depends on the ability to notice yourself before the pattern becomes the path.","speaker":"Reading your result","duration":11000},{"type":"results-launch"}],"archetypes":{"reactive_defender":{"name":"The Cadet Under Fire","band":"Strategic Infancy","headline":"You care about defending the coast — but pressure may be driving more of your strategy than you realise.","body":"Your result suggests that when stakes rise, your attention narrows fast. You may move into reaction, urgency, loyalty, or defence before you have understood what is happening.","risk":"Your risk is not lack of effort. It is pressure-led action. You may be protecting the kingdom while reinforcing the very patterns that weaken it.","focus":"Start at Level 1 — <em>Deepen Self-Awareness</em>. Notice your pressure patterns. Name your triggers. Build a pause before reacting.","next":"Your first breakthrough is likely to come from seeing your own operating system more clearly — before you change anything else."},"tactical_survivor":{"name":"The Coastal Captain","band":"Tactical Survivor","headline":"You can handle pressure — but your command may be too anchored in the immediate engagement.","body":"You are capable, practical, and effective in difficult straits. You make decisions, keep momentum, and solve immediate problems.","risk":"Your risk is tactical over-functioning. You may become so good at surviving the current engagement that you unintentionally normalise crisis as the operating model.","focus":"Strengthen Level 3 — <em>Develop Strategic Capabilities</em>. Focus on future-orientation, creative options, and acting well in uncertainty.","next":"Your growth edge is widening the time horizon you actually think in — from this watch, to this dynasty."},"hidden_drifter":{"name":"The Compromised Commander","band":"Hidden Drift","headline":"You are more strategic than most — but your blindspots may emerge precisely when you feel most certain.","body":"You are thoughtful, capable, and likely well-intentioned. Under pressure, your strengths may distort. Clarity becomes certainty. Decisiveness becomes control.","risk":"Your risk is <em>justified drift</em>. You may continue making decisions that each seem defensible while the wider pattern moves quietly away from your stated values.","focus":"Work across Levels 1 and 2 — <em>Deepen Self-Awareness</em> and <em>Cultivate Open-Mindedness</em>. Watch the moment when \"necessary\" becomes a dangerous word.","next":"Your fastest development will come from learning to notice earlier — before the pattern becomes the path."},"strategic_operator":{"name":"The Squadron Admiral","band":"Strategic Operator","headline":"You show strong strategic capability and a relatively balanced pattern under pressure.","body":"Your result suggests you can remain clear, reflective, and effective in complex situations. Composure under fire, thoughtful decisions, openness to council, alignment with crown and crew — all visible in your pattern.","risk":"Your risk is not capability — it is consistency. Under enough pressure, even strong admirals drift into old patterns.","focus":"Strengthen Level 4 — <em>Scale Your Impact</em>. Decision quality, council alignment, influence without over-control.","next":"Your growth edge is becoming more conscious — and more deliberate — about the impact you already have."},"force_multiplier":{"name":"The Architect of the Fleet","band":"Strategic Force Multiplier","headline":"You do not just think strategically. You increase the strategic capacity of the captains and kingdom around you.","body":"Your result suggests a highly integrated strategic profile. You hold complexity without collapsing into confusion or control.","risk":"Your risk is <em>over-reliance</em>. Others may look to you for clarity, judgement, and steadiness. Over time, that can quietly create dependency.","focus":"Your next level is multiplication. Develop strategic capability in others. Design decision systems.","next":"Your development edge is to become less necessary — by making the fleet more strategically capable."}},"secondaryPatterns":{"architect_of_order":{"name":"The Discipline Hawk","headline":"Drawn to order, command, and decisive action.","body":"You are highly effective in moments of chaos. But unchecked, your strength becomes rigidity."},"the_justifier":{"name":"The Excuses of War","headline":"At risk of rationalising questionable orders when the campaign feels important enough.","body":"This does not mean you lack values. It means your values can become vulnerable when victory, loyalty, or royal pressure enters the room."},"the_calm_blade":{"name":"The Iron Hand","headline":"Composed in moments that unsettle others on the deck.","body":"That composure is valuable. But there is a fine line between regulation and emotional distance."},"the_consensus_seeker":{"name":"The Council Builder","headline":"You create inclusion and invite voice — but may delay difficult orders.","body":"Your development edge is to preserve collaboration while becoming more decisive when the moment closes."},"the_decisive_commander":{"name":"The Cannon's Voice","headline":"You move quickly and bring momentum — but your speed may narrow the field of scouting.","body":"Your edge is to slow down just enough to hear what the sea is trying to tell you."},"vision_under_strain":{"name":"The Strategist Faltering","headline":"You see beyond the immediate engagement, but pressure may disrupt your steadiness on deck.","body":"Your edge is to build inner stability so your vision survives contact with reality."}},"riskCopy":{"control_bias":{"name":"Command Reflex","low":"You appear able to pursue clarity without defaulting to command.","mod":"You may sometimes overvalue speed, certainty, or rank when pressure rises.","high":"You may be at risk of mistaking <em>command for strategy</em>. This can make you decisive — but it may also reduce listening, creativity, and trust on deck.","q":"Where might you be calling something <em>discipline</em> when it is actually obedience?"},"moral_drift":{"name":"Battle Drift","low":"Your responses suggest a relatively strong ability to keep means and ends connected.","mod":"You may occasionally justify difficult orders when the campaign feels important enough.","high":"You may be vulnerable to rationalising harmful choices if they appear necessary for the victory.","q":"At what point does a necessary compromise become a betrayal of the campaign itself?"},"detachment_pressure":{"name":"Iron Composure","low":"You appear able to stay connected to human consequence while under pressure.","mod":"Your composure is a strength, but it may sometimes become distance.","high":"You may remain calm in ways others on deck experience as emotionally unavailable, overly rational, or disconnected from impact.","q":"How do you stay steady without becoming unreachable?"}},"nextSteps":{"reactive_defender":[{"icon":"pause","title":"The five-breath pause","body":"Before responding to a scout report, count five full breaths. Notice what your body wants to do, then choose what to do.","test":"Try for 7 watches. Track each time you used it."},{"icon":"journal","title":"A nightly two-line log","body":"Each evening write: \"Today I noticed…\" and \"Tomorrow I will…\". Build the muscle of self-observation.","test":"Do this for 21 days, then re-read the lot."},{"icon":"mirror","title":"Ask one captain","body":"Ask one trusted captain: \"When pressure rises, what do you see me become on deck?\" Listen without defending.","test":"One question, one person, this week."},{"icon":"question","title":"Replace \"should\" with \"if\"","body":"Notice your \"shoulds\" — they are usually pressure speaking. Reframe to \"if I did this, what would happen?\"","test":"Count your \"shoulds\" for one day. Reframe three."}],"tactical_survivor":[{"icon":"horizon","title":"The ten-year question","body":"On any non-trivial decision, ask: \"What does this look like a decade from now?\"","test":"Apply to your next three meaningful decisions."},{"icon":"experiment","title":"Run one strategic experiment","body":"Pick one current problem. Generate four genuinely different solutions before settling on one.","test":"One problem, four options, this week."},{"icon":"doors","title":"Future-back planning","body":"Describe in detail what good looks like 18 months from now. Then walk backwards: what decision today would matter then?","test":"90 minutes, a single page, by the new moon."},{"icon":"reframe","title":"Trade urgency for importance","body":"For one week, mark every order as either urgent OR important. Notice the ratio.","test":"Audit for 5 days. Drop three urgent-not-important items."}],"hidden_drifter":[{"icon":"notice","title":"The drift word audit","body":"Notice when you use words like \"necessary\", \"no choice\", \"this once\". Each is a possible drift signal.","test":"Track for two weeks. Bring the list to a mentor."},{"icon":"invite","title":"Invite your strongest dissenter","body":"Identify the captain most likely to disagree with you. Invite them into a real decision.","test":"One conversation, this month. Document what shifted."},{"icon":"mirror","title":"The three captains sentence","body":"Ask three captains: \"What is one thing about my pattern under pressure that I probably do not see?\"","test":"Three people, one question, no defending."},{"icon":"pause","title":"Slow down on the certain ones","body":"When a call feels obvious, you are most at risk. Apply a 24-hour rule to anything you are certain about.","test":"Use the rule three times this month."}],"strategic_operator":[{"icon":"multiply","title":"Develop one other officer","body":"Choose one officer in your orbit. Help them build a strategic muscle they currently lack.","test":"Name the person. Name the muscle. Begin."},{"icon":"decide","title":"Make decisions more visible","body":"When you make a meaningful call, share publicly what you considered and what you weighed.","test":"Try this on three decisions this month."},{"icon":"reframe","title":"Sharpen the consequential 20%","body":"Identify the 20% of your decisions that drive 80% of outcomes.","test":"Map your decisions for a week. Re-balance time."},{"icon":"experiment","title":"Pick one risk to deliberately reduce","body":"Look at your three risk overlays. Choose the one closest to becoming a real constraint.","test":"One overlay, one practice, 30 days."}],"force_multiplier":[{"icon":"multiply","title":"Design a decision system","body":"Create a clear template for how strategic decisions get made in your command.","test":"Build the v1 template. Apply to your next big call."},{"icon":"invite","title":"Build the bench","body":"Identify three captains who could become the next layer of strategic capability.","test":"Three names. One conversation each, this month."},{"icon":"mirror","title":"Make yourself less necessary","body":"In every council this month, ask: \"Could someone else here have led this?\"","test":"One month of audit. Hand off two recurring councils."},{"icon":"horizon","title":"Author the long memorial","body":"Write a short paper on the strategic capability you want your wider command to have in three years.","test":"One page. Share with three trusted readers."}]},"imageMap":{"archetypeDir":"images/skin-yi/","scene":{"councilChamber":"images/skin-yi/scene-war-chamber.png","fracturedCity":"images/skin-yi/scene-burning-coast.png","convoyArc":"images/skin-yi/scene-fleet-under-fire.png","privateMeet":"images/skin-yi/scene-private-meeting.png","breakingPoint":"images/skin-yi/scene-admirals-dais.png","confrontation":"images/skin-yi/scene-confrontation.png","twinSuns":"images/skin-yi/scene-yi-cottage.png","summonsHerald":"images/skin-yi/scene-yeosu-overview.png","chaoticCouncil":"images/skin-yi/scene-council-of-captains.png","aftermathMedbay":"images/skin-yi/scene-courtyard-dawn.png","shadowPattern":"images/skin-yi/scene-shadow-pattern.png","alliesWhisper":"images/skin-yi/scene-allies-whisper.png","reckoningMirror":"images/skin-yi/scene-water-basin.png","dividedChamber":"images/skin-yi/scene-divided-court.png"}}};

